INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Booster la performance commerciale avec l''IA', 'Formation sur l’utilisation de l’IA pour booster la performance commerciale, optimiser la prospection et améliorer la relation client.', 14, 450000.00, 'entreprise', '2026-12-20', 30, '2026-01-14 12:38:42', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre l’impact de l’IA sur la performance commerciale\n• Utiliser des outils IA pour automatiser la prospection et le suivi\n• Optimiser le scoring des leads et la conversion client\n• Développer des stratégies commerciales basées sur les données\n• Piloter la performance individuelle et collective grâce à l’IA\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre le rôle de l’IA dans la performance commerciale, utiliser des outils IA pour automatiser et optimiser les processus, améliorer la prospection et la conversion client, développer des stratégies basées sur les données et piloter la performance commerciale.\n\n--- PRÉREQUIS ---\nConnaissances de base en vente ou marketing. Familiarité avec les outils numériques recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA et son impact sur la vente\nModule 2 : Outils IA pour la prospection et le suivi\nModule 3 : Stratégies commerciales assistées par IA\nModule 4 : Optimisation de la relation client\nModule 5 : Pilotage et mesure de la performance commerciale\nModule 6 : Mise en œuvre et bonnes pratiques\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommerciaux, managers, responsables marketing, consultants et toute personne impliquée dans la performance commerciale.\n\n--- MÉTHODES ---\nPrésentations interactives, démonstrations, ateliers pratiques, études de cas, jeux de rôle et simulations commerciales.\n\n--- SUPPORTS ---\nCRM intelligents, chatbots, outils de scoring, dashboards IA, guides pratiques, modèles de suivi client, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
